text:
{{
  inpRecIngQuantity.text && inpRecIngPurchaseCost.text
    ? "Cost / unit " + (() => {
        const qty = Number(inpRecIngQuantity.text);
        const cost = Number(inpRecIngPurchaseCost.text);
        const wastage = Number(inpRecIngWastage.text || 0);

        const netYield = qty * (1 - wastage / 100);

        if (!netYield || netYield <= 0) return "";

        const v = cost / netYield;
        const price = v % 1 === 0 ? v.toFixed(0) : v.toFixed(2);
        const unit = selRecIngPurchaseUnit.selectedOptionLabel || "";

        return unit ? `$${price} / ${unit}` : `$${price}`;
      })()
    : "Cost / unit "
}}
